```astro
---
import { NAV_ITEMS, SITE_CONFIG } from "../../lib/constants";
import Container from "../ui/Container.astro";
import MobileMenu from "./MobileMenu";

interface Props {
  transparent?: boolean;
}

const { transparent = false } = Astro.props;
---

<header
  id="site-header"
  class:list={[
    "fixed top-0 left-0 right-0 z-50 transition-all duration-300",
    transparent ? "bg-transparent" : "bg-white/95 backdrop-blur-sm shadow-sm",
  ]}
>
  <Container>
    <nav class="flex items-center justify-between h-16 lg:h-20">
      <!-- Logo -->
      <a href="/" class="flex items-center gap-2 text-xl font-bold text-sakura-600 hover:text-sakura-700 transition-colors">
        <span class="sr-only">{SITE_CONFIG.name} ホームに戻る</span>
        <span aria-hidden="true">あいのみ</span>
      </a>

      <!-- Desktop Navigation -->
      <ul class="hidden md:flex items-center gap-8">
        {NAV_ITEMS.map((item) => (
          <li class="relative group">
            <a
              href={item.href}
              class="text-neutral-700 hover:text-sakura-600 transition-colors py-2 font-medium"
            >
              {item.label}
            </a>
            {item.children && (
              <ul class="absolute top-full left-0 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200">
                <div class="bg-white rounded-lg shadow-lg border border-neutral-100 py-2 min-w-[180px]">
                  {item.children.map((child) => (
                    <li>
                      <a
                        href={child.href}
                        class="block px-4 py-2 text-neutral-700 hover:text-sakura-600 hover:bg-sakura-50 transition-colors"
                      >
                        {child.label}
                      </a>
                    </li>
                  ))}
                </div>
              </ul>
            )}
          </li>
        ))}
      </ul>

      <!-- Mobile Menu Button -->
      <div class="md:hidden">
        <MobileMenu client:load navItems={NAV_ITEMS} />
      </div>
    </nav>
  </Container>
</header>

<!-- Spacer to prevent content from going under fixed header -->
<div class="h-16 lg:h-20" aria-hidden="true"></div>

<script>
  // Header scroll behavior
  const header = document.getElementById("site-header");
  let lastScrollY = 0;

  const handleScroll = () => {
    const currentScrollY = window.scrollY;

    if (header) {
      // Add background when scrolled
      if (currentScrollY > 50) {
        header.classList.remove("bg-transparent");
        header.classList.add("bg-white/95", "backdrop-blur-sm", "shadow-sm");
      } else if (header.dataset.transparent === "true") {
        header.classList.add("bg-transparent");
        header.classList.remove("bg-white/95", "backdrop-blur-sm", "shadow-sm");
      }
    }

    lastScrollY = currentScrollY;
  };

  window.addEventListener("scroll", handleScroll, { passive: true });
</script>
```

2. Create src/components/common/MobileMenu.tsx:

```tsx
import { useState, useEffect, useCallback } from "react";
import { Menu, X } from "lucide-react";
import type { NavItem } from "../../types/ui";

interface MobileMenuProps {
  navItems: NavItem[];
}

export default function MobileMenu({ navItems }: MobileMenuProps) {
  const [isOpen, setIsOpen] = useState(false);

  const handleClose = useCallback(() => {
    setIsOpen(false);
    document.body.style.overflow = "";
  }, []);

  const handleOpen = useCallback(() => {
    setIsOpen(true);
    document.body.style.overflow = "hidden";
  }, []);

  // Handle escape key
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isOpen) {
        handleClose();
      }
    };

    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, handleClose]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      document.body.style.overflow = "";
    };
  }, []);

  return (
    <>
      {/* Menu Button */}
      <button
        onClick={handleOpen}
        className="p-2 text-neutral-700 hover:text-sakura-600 transition-colors"
        aria-label="メニューを開く"
        aria-expanded={isOpen}
        aria-controls="mobile-menu"
      >
        <Menu className="w-6 h-6" />
      </button>

      {/* Overlay */}
      {isOpen && (
        <div
          className="fixed inset-0 bg-black/50 z-40"
          onClick={handleClose}
          aria-hidden="true"
        />
      )}

      {/* Menu Panel */}
      <div
        id="mobile-menu"
        className={`fixed top-0 right-0 h-full w-[280px] bg-white z-50 transform transition-transform duration-300 ${
          isOpen ? "translate-x-0" : "translate-x-full"
        }`}
        role="dialog"
        aria-modal="true"
        aria-label="ナビゲーションメニュー"
      >
        {/* Close Button */}
        <div className="flex justify-end p-4">
          <button
            onClick={handleClose}
            className="p-2 text-neutral-700 hover:text-sakura-600 transition-colors"
            aria-label="メニューを閉じる"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Navigation */}
        <nav className="px-4">
          <ul className="space-y-2">
            {navItems.map((item) => (
              <li key={item.href}>
                <a
                  href={item.href}
                  className="block px-4 py-3 text-lg text-neutral-700 hover:text-sakura-600 hover:bg-sakura-50 rounded-lg transition-colors"
                  onClick={handleClose}
                >
                  {item.label}
                </a>
                {item.children && (
                  <ul className="ml-4 mt-1 space-y-1">
                    {item.children.map((child) => (
                      <li key={child.href}>
                        <a
                          href={child.href}
                          className="block px-4 py-2 text-neutral-600 hover:text-sakura-600 hover:bg-sakura-50 rounded-lg transition-colors"
                          onClick={handleClose}
                        >
                          {child.label}
                        </a>
                      </li>
                    ))}
                  </ul>
                )}
              </li>
            ))}
          </ul>
        </nav>
      </div>
    </>
  );
}
```

